#include <stdio.h>
#include <string.h>
#define MAX 100
int main() {
    int n;
    scanf("%d", &n);
    char s[MAX][11];
    for (int i = 0; i < n; i++) {
        scanf("%s", s[i]);
    }
    for (int i = 0; i < n; i++) {
        int count = 0;
        for (int j = 0; j < n; j++) {
            if (strcmp(s[i], s[j]) == 0) {
                count++;
            }
        }
        printf("%d %s\n", count, s[i]);
    }
    return 0;
}

