code.JavaScript:
const readline = require('readline');
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});
let n;
let m = {};
let i = 0;
rl.on('line', (line) => {
    if (i === 0) {
        n = parseInt(line);
    } else {
        let s = line;
        if (s in m) {
            m[s]++;
        } else {
            m[s] = 1;
        }
        if (i === n) {
            for (let key in m) {
                console.log(m[key] + " " + key);
            }
            rl.close();
        }
    }
    i++;
});

